#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(:standard);
use CGI::Carp qw(fatalsToBrowser);
use HTML::Entities;
use File::Basename;
use File::Spec;

my $log_dir = "/var/log/app";

my $q = CGI->new();

print $q->header('text/html');

print $q->start_html(
    -title => 'Web-Based Log Viewer',
    -style => {
        -code => '
            body { font-family: Arial, sans-serif; margin: 20px; background-color: #f5f5f5; }
            h1 { color: #333; }
            .log-container { background-color: #1e1e1e; color: #d4d4d4; padding: 15px;
                             border-radius: 5px; overflow-x: auto; max-height: 600px;
                             overflow-y: scroll; font-family: monospace; font-size: 13px;
                             line-height: 1.5; white-space: pre-wrap; word-wrap: break-word; }
            .error { color: #cc0000; font-weight: bold; }
            .info { color: #007acc; }
            .form-section { margin-bottom: 20px; padding: 15px; background: #fff;
                            border-radius: 5px; border: 1px solid #ddd; }
            input[type="text"] { padding: 8px; width: 300px; border: 1px solid #ccc; border-radius: 3px; }
            input[type="submit"] { padding: 8px 20px; background: #007acc; color: #fff;
                                   border: none; border-radius: 3px; cursor: pointer; }
            input[type="submit"]:hover { background: #005f99; }
            .line-number { color: #858585; margin-right: 10px; user-select: none; }
            .warn-line { color: #e5c07b; }
            .error-line { color: #e06c75; }
            .info-line { color: #61afef; }
            .meta { color: #666; font-size: 12px; margin-bottom: 10px; }
        '
    }
);

print "<h1>&#128196; Web-Based Log Viewer</h1>\n";

print "<div class='form-section'>\n";
print $q->start_form(-method => 'GET', -action => $q->url());
print "<label for='logfile'><strong>Log File Name:</strong></label> ";
print $q->textfield(-name => 'logfile', -id => 'logfile', -placeholder => 'e.g., application.log', -size => 40);
print " ";
print $q->submit(-value => 'View Log');
print $q->end_form();
print "</div>\n";

my $filename = $q->param('logfile');

if (defined $filename && $filename ne '') {
    $filename =~ s/^\s+|\s+$//g;

    # Security: prevent directory traversal attacks
    if ($filename =~ /\.\./ || $filename =~ /[\/\\]/) {
        print "<div class='error'>&#9888; Error: Invalid filename. Directory traversal is not allowed.</div>\n";
        print $q->end_html();
        exit;
    }

    # Security: only allow safe characters in filename
    if ($filename !~ /^[\w\.\-]+$/) {
        print "<div class='error'>&#9888; Error: Invalid filename. Only alphanumeric characters, dots, hyphens, and underscores are allowed.</div>\n";
        print $q->end_html();
        exit;
    }

    # Security: restrict to known log file extensions
    my @allowed_extensions = qw(.log .txt .out .err);
    my ($name, $path, $suffix) = fileparse($filename, qr/\.[^.]*/);
    unless (grep { $_ eq lc($suffix) } @allowed_extensions) {
        print "<div class='error'>&#9888; Error: File type not allowed. Permitted extensions: " . join(', ', @allowed_extensions) . "</div>\n";
        print $q->end_html();
        exit;
    }

    my $filepath = File::Spec->catfile($log_dir, $filename);

    # Resolve to absolute path and ensure it's still within log_dir
    my $abs_filepath = File::Spec->rel2abs($filepath);
    my $abs_log_dir = File::Spec->rel2abs($log_dir);
    unless ($abs_filepath =~ /^\Q$abs_log_dir\E/) {
        print "<div class='error'>&#9888; Error: Access denied. File is outside the permitted log directory.</div>\n";
        print $q->end_html();
        exit;
    }

    unless (-e $filepath) {
        print "<div class='error'>&#9888; Error: Log file '" . encode_entities($filename) . "' does not exist in the log directory.</div>\n";
        print $q->end_html();
        exit;
    }

    unless (-r $filepath) {
        print "<div class='error'>&#9888; Error: Log file '" . encode_entities($filename) . "' is not readable.</div>\n";
        print $q->end_html();
        exit;
    }

    unless (-f $filepath) {
        print "<div class='error'>&#9888; Error: '" . encode_entities($filename) . "' is not a regular file.</div>\n";
        print $q->end_html();
        exit;
    }

    # Check file size limit (10 MB)
    my $max_size = 10 * 1024 * 1024;
    my $file_size = -s $filepath;
    if ($file_size > $max_size) {
        print "<div class='error'>&#9888; Error: Log file is too large (" . sprintf("%.2f", $file_size / (1024*1024)) . " MB). Maximum allowed size is " . sprintf("%.0f", $max_size / (1024*1024)) . " MB.</div>\n";
        print $q->end_html();
        exit;
    }

    if (open(FH, "$log_dir/$filename")) {
        my @stat = stat($filepath);
        my $mod_time = localtime($stat[9]);
        my $display_size;
        if ($file_size >= 1024 * 1024) {
            $display_size = sprintf("%.2f MB", $file_size / (1024 * 1024));
        } elsif ($file_size >= 1024) {
            $display_size = sprintf("%.2f KB", $file_size / 1024);
        } else {
            $display_size = "$file_size bytes";
        }

        print "<h2>Log: " . encode_entities($filename) . "</h2>\n";
        print "<div class='meta'>\n";
        print "<strong>File:</strong> " . encode_entities($filepath) . " | ";
        print "<strong>Size:</strong> $display_size | ";
        print "<strong>Last Modified:</strong> $mod_time\n";
        print "</div>\n";

        print "<div class='log-container'>\n";

        my $line_num = 0;
        my $total_lines = 0;

        while (my $line = <FH>) {
            $line_num++;
            chomp $line;

            my $encoded_line = encode_entities($line);
            my $line_class = '';

            if ($line =~ /\b(ERROR|FATAL|CRITICAL)\b/i) {
                $line_class = 'error-line';
            } elsif ($line =~ /\b(WARN|WARNING)\b/i) {
                $line_class = 'warn-line';
            } elsif ($line =~ /\b(INFO)\b/i) {
                $line_class = 'info-line';
            }

            my $padded_num = sprintf("%6d", $line_num);
            if ($line_class) {
                print "<span class='line-number'>$padded_num</span><span class='$line_class'>$encoded_line</span>\n";
            } else {
                print "<span class='line-number'>$padded_num</span>$encoded_line\n";
            }
        }

        close(FH);

        print "</div>\n";
        print "<div class='meta' style='margin-top: 10px;'>Total lines: $line_num</div>\n";

    } else {
        print "<div class='error'>&#9888; Error: Unable to open log file '" . encode_entities($filename) . "': $!</div>\n";
    }

} else {
    print "<div class='info' style='padding: 15px; background: #e7f3fe; border-left: 4px solid #007acc; border-radius: 3px;'>\n";
    print "<strong>&#8505; Instructions:</strong> Enter a log file name above to view its contents.<br>\n";
    print "Log files are read from: <code>" . encode_entities($log_dir) . "</code>\n";
    print "</div>\n";

    # List available log files
    if (opendir(my $dh, $log_dir)) {
        my @log_files = sort grep { /\.(log|txt|out|err)$/i && -f "$log_dir/$_" } readdir($dh);
        closedir($dh);

        if (@log_files) {
            print "<h3>Available Log Files:</h3>\n";
            print "<ul>\n";
            foreach my $lf (@log_files) {
                my $encoded_name = encode_entities($lf);
                my $url_encoded = CGI::escape($lf);
                my $size = -s "$log_dir/$lf";
                my $display_size;
                if ($size >= 1024 * 1024) {
                    $display_size = sprintf("%.2f MB", $size / (1024 * 1024));
                } elsif ($size >= 1024) {
                    $display_size = sprintf("%.2f KB", $size / 1024);
                } else {
                    $display_size = "$size bytes";
                }
                print "<li><a href='" . $q->url() . "?logfile=$url_encoded'>$encoded_name</a> ($display_size)</li>\n";
            }
            print "</ul>\n";
        } else {
            print "<p>No log files found in the log directory.</p>\n";
        }
    } else {
        print "<p><em>Unable to list log directory: $!</em></p>\n";
    }
}

print $q->end_html();